text:
Hi,
If you know the vendor and product IDs, then you shouldn't match for uftdiX at all.

Use:

notify 50 {
       match "system"          "USB";
       match "subsystem"       "DEVICE";
       match "type"            "ATTACH";
       match "vendor"          "0x1781";
       match "product"         "0x0c30";
       action "chgrp dialer /dev/$cdev; chmod 660 /dev/$cdev";
};

--HPS
